<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Falling Sand Sandbox</title>
    <style>
        :root {
            --bg-color: #121212;
            --card-bg: #1e1e1e;
            --text-color: #e0e0e0;
            --accent-color: #bb86fc;
            --sand-color: #e3b878;
            --water-color: #4a90e2;
            --wall-color: #555555;
            --acid-color: #a3ff00;
        }

        body {
            margin: 0;
            padding: 0;
            background-color: var(--bg-color);
            color: var(--text-color);
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
            display: flex;
            flex-direction: column;
            align-items: center;
            justify-content: center;
            height: 100vh;
            overflow: hidden;
        }

        .container {
            display: flex;
            flex-direction: column;
            align-items: center;
            gap: 20px;
            padding: 20px;
            background: var(--card-bg);
            border-radius: 16px;
            box-shadow: 0 10px 30px rgba(0,0,0,0.5);
        }

        canvas {
            border: 2px solid #333;
            border-radius: 8px;
            image-rendering: pixelated;
            cursor: crosshair;
            background-color: #000;
            max-width: 90vw;
            max-height: 70vh;
        }

        .controls {
            display: flex;
            flex-wrap: wrap;
            justify-content: center;
            gap: 10px;
            max-width: 500px;
        }

        button {
            padding: 12px 20px;
            border: none;
            border-radius: 8px;
            font-weight: bold;
            cursor: pointer;
            transition: transform 0.1s, filter 0.2s;
            text-transform: uppercase;
            letter-spacing: 1px;
            font-size: 0.8rem;
        }

        button:active {
            transform: scale(0.95);
        }

        button.selected {
            outline: 3px solid white;
            filter: brightness(1.2);
        }

        #mat-sand { background-color: var(--sand-color); color: #000; }
        #mat-water { background-color: var(--water-color); color: #fff; }
        #mat-wall { background-color: var(--wall-color); color: #fff; }
        #mat-acid { background-color: var(--acid-color); color: #000; }
        #mat-empty { background-color: #444; color: #fff; }
        #clear { background-color: #cf6679; color: #fff; }

        .title {
            margin: 0;
            font-size: 1.5rem;
            font-weight: bold;
            color: var(--accent-color);
        }
    </style>
</head>
<body>

<div class="container">
    <h1 class="title">Sand Sandbox</h1>
    <canvas id="sand" width="400" height="400"></canvas>
    <div class="controls">
        <button id="mat-sand" class="material-btn selected">Sand</button>
        <button id="mat-water" class="material-btn">Water</button>
        <button id="mat-wall" class="material-btn">Wall</button>
        <button id="mat-acid" class="material-btn">Acid</button>
        <button id="mat-empty" class="material-btn">Eraser</button>
        <button id="clear">Clear All</button>
    </div>
</div>

<script>
    const canvas = document.getElementById('sand');
    const ctx = canvas.getContext('2d', { alpha: false });
    const w_css = 400;
    const h_css = 400;

    // Simulation constants
    const W = 100; // Grid width
    const H = 100; // Grid height
    const SCALE = w_css / W;

    const EMPTY = 0, SAND = 1, WATER = 2, WALL = 3, ACID = 4;
    const MAT_NAMES = ["empty", "sand", "water", "wall", "acid"];
    const COLORS = ["#000000", "#e3b878", "#4a90e2", "#555555", "#a3ff00"];

    // State
    let grid = Array.from({ length: H }, () => new Int8Array(W));
    let nextGrid = Array.from({ length: H }, () => new Int8Array(W));

    // API Object
    window.sim = {
        w: W,
        h: H,
        get(x, y) {
            if (x < 0 || x >= W || y < 0 || y >= H) return "empty";
            return MAT_NAMES[grid[y][x]];
        },
        set(x, y, material) {
            if (x < 0 || x >= W || y < 0 || y >= H) return;
            const idx = MAT_NAMES.indexOf(material);
            if (idx !== -1) grid[y][x] = idx;
        },
        clear() {
            for (let y = 0; y < H; y++) grid[y].fill(EMPTY);
            render();
        },
        tick(n) {
            for (let i = 0; i < n; i++) {
                update();
            }
            render();
        }
    };

    function update() {
        // Copy current to next for double buffering
        for (let y = 0; y < H; y++) {
            nextGrid[y].set(grid[y]);
        }

        // 1. Acid Dissolution Logic
        for (let y = 0; y < H; y++) {
            for (let x = 0; x < W; x++) {
                if (grid[y][x] === ACID) {
                    const neighbors = [[0, 1], [1, 0], [-1, 0]]; // below, right, left
                    for (let [dx, dy] of neighbors) {
                        let nx = x + dx, ny = y + dy;
                        if (nx >= 0 && nx < W && ny >= 0 && ny < H) {
                            const target = grid[ny][nx];
                            if (target === SAND || target === WALL) {
                                nextGrid[ny][nx] = EMPTY;
                            }
                        }
                    }
                }
            }
        }

        // 2. Movement Logic (Bottom-Up Processing)
        for (let y = H - 1; y >= 0; y--) {
            for (let x = 0; x < W; x++) {
                const m = grid[y][x];
                if (m === EMPTY || m === WALL) continue;

                if (m === SAND) {
                    // Sand falls down or slides diagonally
                    if (isPassable(x, y + 1)) {
                        let targetM = grid[y+1][x];
                        nextGrid[y+1][x] = SAND;
                        nextGrid[y][x] = (targetM === WATER || targetM === ACID) ? targetM : EMPTY;
                    } else {
                        let dx = Math.random() < 0.5 ? -1 : 1;
                        if (isPassable(x + dx, y + 1)) {
                            let targetM = grid[y+1][x+dx];
                            nextGrid[y+1][x+dx] = SAND;
                            nextGrid[y][x] = (targetM === WATER || targetM === ACID) ? targetM : EMPTY;
                        } else if (isPassable(x - dx, y + 1)) {
                            let targetM = grid[y+1][x-dx];
                            nextGrid[y+1][x-dx] = SAND;
                            nextGrid[y][x] = (targetM === WATER || targetM === ACID) ? targetM : EMPTY;
                        }
                    }
                } else if (m === WATER || m === ACID) {
                    // Water/Acid falls down or spreads horizontally
                    if (isPassable(x, y + 1)) {
                        let targetM = grid[y+1][x];
                        nextGrid[y+1][x] = m;
                        nextGrid[y][x] = (targetM === WATER || targetM === ACID) ? targetM : EMPTY;
                    } else {
                        let dx = Math.random() < 0.5 ? -1 : 1;
                        if (isPassable(x + dx, y)) {
                            let targetM = grid[y][x+dx];
                            nextGrid[y][x+dx] = m;
                            nextGrid[y][x] = (targetM === WATER || targetM === ACID) ? targetM : EMPTY;
                        } else if (isPassable(x - dx, y)) {
                            let targetM = grid[y][x-dx];
                            nextGrid[y][x-dx] = m;
                            nextGrid[y][x] = (targetM === WATER || targetM === ACID) ? targetM : EMPTY;
                        }
                    }
                }
            }
        }

        // Swap buffers
        let temp = grid;
        grid = nextGrid;
        nextGrid = temp;
    }

    function isPassable(x, y) {
        if (x < 0 || x >= W || y < 0 || y >= H) return false;
        const m = grid[y][x];
        return m === EMPTY || m === WATER || m === ACID;
    }

    function render() {
        ctx.fillStyle = "#000";
        ctx.fillRect(0, 0, w_css, h_css);
        for (let y = 0; y < H; y++) {
            for (let x = 0; x < W; x++) {
                const m = grid[y][x];
                if (m !== EMPTY) {
                    ctx.fillStyle = COLORS[m];
                    ctx.fillRect(x * SCALE, y * SCALE, SCALE, SCALE);
                }
            }
        }
    }

    // Interaction logic
    let isMouseDown = false;
    let currentMat = SAND;

    const handleInput = (e) => {
        const rect = canvas.getBoundingClientRect();
        const mouseX = (e.clientX - rect.left) * (W / rect.width);
        const mouseY = (e.clientY - rect.top) * (H / rect.height);

        // Paint a small brush area
        for(let dy = -1; dy <= 1; dy++) {
            for(let dx = -1; dx <= 1; dx++) {
                window.sim.set(Math.floor(mouseX + dx), Math.floor(mouseY + dy), MAT_NAMES[currentMat]);
            }
        }
        render();
    };

    canvas.addEventListener('mousedown', (e) => { isMouseDown = true; handleInput(e); });
    window.addEventListener('mouseup', () => { isMouseDown = false; });
    canvas.addEventListener('mousemove', (e) => { if (isMouseDown) handleInput(e); });

    // UI Logic
    document.querySelectorAll('.material-btn').forEach(btn => {
        btn.addEventListener('click', () => {
            document.querySelectorAll('.material-btn').forEach(b => b.classList.remove('selected'));
            btn.classList.add('selected');
            currentMat = MAT_NAMES.indexOf(btn.id.replace('mat-', ''));
            if (btn.id === 'mat-empty') currentMat = EMPTY;
        });
    });

    document.getElementById('clear').addEventListener('click', () => {
        window.sim.clear();
    });

    // Animation loop
    function loop() {
        window.sim.tick(1);
        requestAnimationFrame(loop);
    }

    // Initial render
    render();
    loop();

</script>
</body>
</html>
